window.docContents[191].resolve({"/Elementary-Number-Theory/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elementary-Number-Theory":{"contents":"This chapter covers the elementary core of number theory as it is formalised in mathlib: divisibility and the Euclidean algorithm, the fundamental theorem of arithmetic, congruences and the structure of the residue rings , arithmetic functions and Dirichlet convolution, quadratic residues and reciprocity, and the classical Diophantine results on sums of squares, Pythagorean triples, and Fermat and Mersenne numbers. Throughout,  denotes a prime,  the integers, and for a positive integer  we write  for the ring of integers modulo  and  for its group of units. Every proof sketch below follows the argument used in the cited mathlib declaration, naming the lemmas that proof actually invokes.\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean","header":"1. Elementary Number Theory","id":"/Elementary-Number-Theory/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elementary-Number-Theory"}});